1	//! Physical frame allocator — 4 KiB granule, intrusive free list + per-region
2	//! bump pointers seeded from Limine's memmap.
3	//!
4	//! The allocator's state is just two pieces:
5	//!  - a `[Region; MAX_REGIONS]` array of `(next_free_pa, end_pa)` bump
6	//!    pointers, one per `MEMMAP_USABLE` region Limine reported;
7	//!  - a single free-list head pointer (kernel virtual address, HHDM-relative)
8	//!    of recently-freed frames.
9	//!
10	//! Allocation prefers the free list; if empty, bumps the first region with
11	//! room. Freed frames are pushed onto the free list — each frame's first
12	//! 8 bytes hold a pointer to the next free frame (the classic intrusive
13	//! free-list trick). This means each frame must be at least 8 bytes — which
14	//! is trivially true at 4 KiB.
15	//!
16	//! Capacity: MAX_REGIONS = 16 is enough for QEMU virt aarch64 (typically
17	//! 2–3 USABLE regions) and Apple Silicon QEMU (similar). If a board ever
18	//! reports more, `init_from_limine_memmap` panics with a clear message
19	//! pointing at this constant.
20	//!
21	//! Concurrency: single-threaded boot. The allocator is wrapped in an
22	//! `UnsafeCell` newtype with `unsafe impl Sync`, matching the convention
23	//! documented on [`crate::proc::table`]. Phase 3.2+'s page-fault flow runs
24	//! the allocator outside fault context — the handler sets `RTS_PAGEFAULT`
25	//! and returns to the scheduler, which then runs VM (or the kernel
26	//! resolver), which calls the allocator. The allocator therefore never
27	//! re-enters from an IRQ or fault.
28	
29	use core::cell::UnsafeCell;
30	use core::ptr;
31	
32	use crate::arch::aarch64::limine::{MEMMAP_USABLE, memmap_entries};
33	
34	/// 4 KiB page / frame size, in bytes.
35	pub const FRAME_SIZE: usize = 4096;
36	
37	/// Maximum number of `MEMMAP_USABLE` regions the allocator can track.
38	const MAX_REGIONS: usize = 16;
39	
40	/// Identifies one 4 KiB physical frame by its page-frame number (PA >> 12).
41	#[derive(Copy, Clone, PartialEq, Eq, Debug)]
42	pub struct Frame(u64);
43	
44	impl Frame {
45	    /// Construct from a physical address. The address must be 4 KiB-aligned
46	    /// — non-aligned values are rejected at construction so downstream
47	    /// callers can rely on `frame.addr()` returning an aligned PA.
48	    pub const fn from_addr(pa: u64) -> Self {
49	        assert!(pa & (FRAME_SIZE as u64 - 1) == 0, "Frame::from_addr: PA not 4 KiB aligned");
50	        Self(pa >> 12)
51	    }
52	
53	    /// Physical address of this frame.
54	    pub const fn addr(self) -> u64 {
55	        self.0 << 12
56	    }
57	}
58	
59	#[derive(Copy, Clone)]
60	struct Region {
61	    /// Next PA to hand out from this region; 0 means "region unused".
62	    next_free_pa: u64,
63	    /// One-past-the-last PA in this region.
64	    end_pa: u64,
65	}
66	
67	const EMPTY_REGION: Region = Region {
68	    next_free_pa: 0,
69	    end_pa: 0,
70	};
71	
72	struct Allocator {
73	    regions: [Region; MAX_REGIONS],
74	    region_count: usize,
75	    /// Head of the free list, as an HHDM virtual address (so we can deref
76	    /// it directly without redoing the HHDM math on each `alloc_frame`).
77	    /// `null` means the free list is empty.
78	    free_head: *mut FreeNode,
79	    /// Statistics for diagnostics — incremented on every alloc/free.
80	    allocs: u64,
81	    frees: u64,
82	}
83	
84	#[repr(C)]
85	struct FreeNode {
86	    next: *mut FreeNode,
87	}
88	
89	#[repr(transparent)]
90	struct AllocatorCell(UnsafeCell<Allocator>);
91	// SAFETY: single-threaded boot invariant; see module-level comment.
92	unsafe impl Sync for AllocatorCell {}
93	
94	static ALLOC: AllocatorCell = AllocatorCell(UnsafeCell::new(Allocator {
95	    regions: [EMPTY_REGION; MAX_REGIONS],
96	    region_count: 0,
97	    free_head: ptr::null_mut(),
98	    allocs: 0,
99	    frees: 0,
100	}));
101	
102	/// Populate the allocator from Limine's memmap. Must be called once during
103	/// boot, before any [`alloc_frame`] / [`free_frame`] call.
104	///
105	/// `hhdm_offset` is Limine's HHDM offset (also passed to
106	/// [`crate::mm::set_hhdm_offset`] separately so the allocator can dereference
107	/// freed-frame pointers into a kernel VA).
108	///
109	/// SAFETY: must be called exactly once, single-threaded, after
110	/// [`crate::mm::set_hhdm_offset`].
111	pub unsafe fn init_from_limine_memmap() {
112	    let entries = match memmap_entries() {
113	        Some(it) => it,
114	        None => panic!("Limine did not populate the memmap response"),
115	    };
116	
117	    // SAFETY: single-threaded boot, single writer.
118	    let a = unsafe { &mut *ALLOC.0.get() };
119	
120	    for entry in entries {
121	        if entry.kind != MEMMAP_USABLE {
122	            continue;
123	        }
124	        // Limine guarantees USABLE entries are 4 KiB-aligned in both base
125	        // and length — verify rather than silently dropping bytes.
126	        let base = entry.base;
127	        let len = entry.length;
128	        assert!(
129	            base & (FRAME_SIZE as u64 - 1) == 0,
130	            "Limine USABLE base {base:#x} is not 4 KiB-aligned"
131	        );
132	        assert!(
133	            len & (FRAME_SIZE as u64 - 1) == 0,
134	            "Limine USABLE length {len:#x} is not 4 KiB-aligned"
135	        );
136	        if len == 0 {
137	            continue;
138	        }
139	        assert!(
140	            a.region_count < MAX_REGIONS,
141	            "Limine reported more than MAX_REGIONS={MAX_REGIONS} usable regions; \
142	             grow the constant in mm::frame"
143	        );
144	        a.regions[a.region_count] = Region {
145	            next_free_pa: base,
146	            end_pa: base.checked_add(len).expect("USABLE region overflows u64"),
147	        };
148	        a.region_count += 1;
149	    }
150	
151	    assert!(
152	        a.region_count > 0,
153	        "Limine memmap contains no MEMMAP_USABLE regions"
154	    );
155	}
156	
157	/// Allocate one 4 KiB frame. Returns `None` if no physical memory remains
158	/// (both the free list and every bump region are exhausted).
159	pub fn alloc_frame() -> Option<Frame> {
160	    // SAFETY: single-threaded boot invariant; see module-level comment.
161	    let a = unsafe { &mut *ALLOC.0.get() };
162	
163	    // Free list takes priority — recently freed frames are still cache-hot.
164	    if !a.free_head.is_null() {
165	        // SAFETY: free_head is either null or an HHDM-VA pointer we set on a
166	        // previous `free_frame`. Reading the first 8 bytes of a free frame
167	        // through HHDM is sound because the frame is unmapped from all
168	        // address spaces (free means free) and HHDM is the only mapping.
169	        let node = a.free_head;
170	        let next = unsafe { (*node).next };
171	        a.free_head = next;
172	        a.allocs += 1;
173	        let pa = hhdm_vaddr_to_pa(node as u64);
174	        return Some(Frame::from_addr(pa));
175	    }
176	
177	    // Otherwise bump from the first region with room.
178	    for r in &mut a.regions[..a.region_count] {
179	        if r.next_free_pa < r.end_pa {
180	            let pa = r.next_free_pa;
181	            r.next_free_pa += FRAME_SIZE as u64;
182	            a.allocs += 1;
183	            // Zero the frame on first hand-out. Page-table walkers expect
184	            // intermediate tables to start all-invalid, and zero pages are
185	            // what user-mode brk/mmap expects too. Cost: one 4 KiB write,
186	            // amortized over the frame's lifetime.
187	            // SAFETY: HHDM covers this PA (Limine base revision 2 blanket-maps
188	            // [0, 4 GiB)), and the frame is exclusively ours.
189	            unsafe {
190	                let dst = crate::mm::phys_to_hhdm(pa) as *mut u64;
191	                for i in 0..(FRAME_SIZE / 8) {
192	                    ptr::write_volatile(dst.add(i), 0);
193	                }
194	            }
195	            return Some(Frame::from_addr(pa));
196	        }
197	    }
198	    None
199	}
200	
201	/// Return one 4 KiB frame to the allocator. The frame is pushed onto the
202	/// free list; future `alloc_frame` calls will hand it back out (zeroed —
203	/// we re-zero on the alloc side, not the free side, so callers can free
204	/// without thinking about residual state).
205	///
206	/// Panics if `frame` lies outside the union of all tracked regions — that
207	/// would mean a caller forged a frame from a non-USABLE PA.
208	pub fn free_frame(frame: Frame) {
209	    let pa = frame.addr();
210	
211	    // SAFETY: single-threaded boot invariant.
212	    let a = unsafe { &mut *ALLOC.0.get() };
213	
214	    // Bounds-check against tracked regions.
215	    let mut in_range = false;
216	    for r in &a.regions[..a.region_count] {
217	        // Region originally spanned [base, end_pa); after bump-allocation
218	        // `next_free_pa` may have advanced. The frame must still satisfy
219	        // base ≤ pa < end_pa — we don't reconstruct `base` (it equals the
220	        // original `next_free_pa`), so checking `pa < end_pa` together with
221	        // "pa was alloc-able from somewhere" is enough.
222	        if pa < r.end_pa {
223	            in_range = true;
224	            break;
225	        }
226	    }
227	    assert!(in_range, "free_frame: PA {pa:#x} is outside all USABLE regions");
228	
229	    // Push onto the free list via HHDM.
230	    let vaddr = crate::mm::phys_to_hhdm(pa) as *mut FreeNode;
231	    // SAFETY: the frame is now owned by the allocator (caller relinquishes
232	    // it). HHDM mapping guarantees the VA is readable+writable.
233	    unsafe {
234	        (*vaddr).next = a.free_head;
235	    }
236	    a.free_head = vaddr;
237	    a.frees += 1;
238	}
239	
240	fn hhdm_vaddr_to_pa(vaddr: u64) -> u64 {
241	    // HHDM is a flat shift; reversing is sub.
242	    vaddr - crate::mm::hhdm_offset()
243	}
