    // it). HHDM mapping guarantees the VA is readable+writable.
    unsafe {
        (*vaddr).next = a.free_head;
    }
    a.free_head = vaddr;
    a.frees += 1;
}

fn hhdm_vaddr_to_pa(vaddr: u64) -> u64 {
    // HHDM is a flat shift; reversing is sub.
    vaddr - crate::mm::hhdm_offset()
