    // a block (large-page support, identity ranges, etc.). (L3 page
    // descriptors also have PTE_TABLE=1, but we never call `next_table`
    // at L3.)
    if desc & PTE_TABLE == 0 {
        return None;
    }
    Some(desc & PA_MASK)
}

